// Menu.jsx — Interactive menu cards with hover tilt + stagger
import { useState, useRef } from 'react';
import { motion } from 'framer-motion';
import useScrollAnimation from '../hooks/useScrollAnimation';

const CATEGORIES = ['All', 'Espresso', 'Pour Over', 'Cold Brew', 'Pastries'];

const MENU_ITEMS = [
  {
    id: 1, category: 'Espresso',
    name: 'Noir Espresso', price: '$5.50',
    desc: 'A bold, velvety double shot from our Ethiopian Yirgacheffe single-origin, with notes of dark chocolate and bergamot.',
    image: 'https://images.unsplash.com/photo-1510591509098-f4fdc6d0ff04?w=600&q=80&auto=format',
    tag: 'Signature',
  },
  {
    id: 2, category: 'Espresso',
    name: 'Velvet Flat White', price: '$6.50',
    desc: 'Silky microfoam milk over a ristretto base. Delicate balance of sweetness and intensity.',
    image: 'https://images.unsplash.com/photo-1571091655789-405eb7a3a3a8?w=600&q=80&auto=format',
    tag: 'Bestseller',
  },
  {
    id: 3, category: 'Pour Over',
    name: 'Golden Ratio V60', price: '$8.00',
    desc: 'Kenyan AA beans brewed at precisely 93°C. Bright acidity, red currant finish, clear cup.',
    image: 'https://images.unsplash.com/photo-1495474472287-4d71bcdd2085?w=600&q=80&auto=format',
    tag: 'Specialty',
  },
  {
    id: 4, category: 'Cold Brew',
    name: 'Midnight Cold Brew', price: '$7.00',
    desc: '18-hour cold steep of our Colombian dark roast. Smooth, chocolatey, zero bitterness.',
    image: 'https://images.unsplash.com/photo-1461023058943-07fcbe16d735?w=600&q=80&auto=format',
    tag: 'New',
  },
  {
    id: 5, category: 'Pour Over',
    name: 'Chemex Reserve', price: '$9.00',
    desc: 'Panama Gesha through our hand-bonded Chemex. Jasmine, white peach, and honey sweetness.',
    image: 'https://images.unsplash.com/photo-1517701604599-bb29b565090c?w=600&q=80&auto=format',
    tag: 'Limited',
  },
  {
    id: 6, category: 'Pastries',
    name: 'Cardamom Kouign-Amann', price: '$6.00',
    desc: 'Caramelized layers of laminated dough with French butter, cardamom, and fleur de sel.',
    image: 'https://images.unsplash.com/photo-1509440159596-0249088772ff?w=600&q=80&auto=format',
    tag: 'Chef\'s Pick',
  },
];

// Tilt on hover
function TiltCard({ children, style }) {
  const [tilt, setTilt] = useState({ x: 0, y: 0 });
  const cardRef = useRef(null);

  const handleMove = (e) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width - 0.5;
    const y = (e.clientY - rect.top) / rect.height - 0.5;
    setTilt({ x: y * -8, y: x * 8 });
  };

  return (
    <div
      ref={cardRef}
      onMouseMove={handleMove}
      onMouseLeave={() => setTilt({ x: 0, y: 0 })}
      style={{
        ...style,
        transform: `perspective(1000px) rotateX(${tilt.x}deg) rotateY(${tilt.y}deg)`,
        transition: tilt.x === 0 ? 'transform 0.5s ease' : 'transform 0.1s linear',
      }}
    >
      {children}
    </div>
  );
}

export default function Menu() {
  const [activeCategory, setActiveCategory] = useState('All');
  const [sectionRef, inView] = useScrollAnimation(0.1);

  const filtered = activeCategory === 'All'
    ? MENU_ITEMS
    : MENU_ITEMS.filter(i => i.category === activeCategory);

  const containerVariants = {
    hidden: {},
    visible: { transition: { staggerChildren: 0.1 } },
  };
  const itemVariants = {
    hidden: { opacity: 0, y: 40 },
    visible: { opacity: 1, y: 0, transition: { duration: 0.7, ease: [0.22, 1, 0.36, 1] } },
  };

  return (
    <section id="menu" style={{ background: '#0f0a07', padding: 'clamp(80px,10vw,140px) clamp(24px,6vw,80px)' }}>
      <div ref={sectionRef} style={{ maxWidth: 1200, margin: '0 auto' }}>
        {/* Section Header */}
        <motion.div
          initial={{ opacity: 0, y: 30 }}
          animate={inView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.8 }}
          style={{ marginBottom: 64, textAlign: 'center' }}
        >
          <p style={{ fontFamily: "'Jost', sans-serif", fontSize: '10px', letterSpacing: '0.35em', color: '#c9a96e', textTransform: 'uppercase', marginBottom: 16 }}>
            Crafted with Intention
          </p>
          <h2 style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: 'clamp(40px, 6vw, 72px)', fontWeight: 300, color: '#f5ead8', lineHeight: 1 }}>
            Our Menu
          </h2>
          <div style={{ width: 40, height: 1, background: '#c9a96e', margin: '24px auto 0' }} />
        </motion.div>

        {/* Category Tabs */}
        <motion.div
          initial={{ opacity: 0 }}
          animate={inView ? { opacity: 1 } : {}}
          transition={{ delay: 0.2 }}
          style={{ display: 'flex', gap: 8, flexWrap: 'wrap', justifyContent: 'center', marginBottom: 56 }}
        >
          {CATEGORIES.map(cat => (
            <button
              key={cat}
              onClick={() => setActiveCategory(cat)}
              style={{
                fontFamily: "'Jost', sans-serif",
                fontSize: '10px', letterSpacing: '0.2em', textTransform: 'uppercase',
                padding: '8px 20px', border: 'none', cursor: 'none',
                background: activeCategory === cat ? '#c9a96e' : 'transparent',
                color: activeCategory === cat ? '#0f0a07' : 'rgba(201,169,110,0.6)',
                borderBottom: activeCategory !== cat ? '1px solid rgba(201,169,110,0.2)' : 'none',
                transition: 'all 0.3s',
              }}
            >
              {cat}
            </button>
          ))}
        </motion.div>

        {/* Cards Grid */}
        <motion.div
          key={activeCategory}
          variants={containerVariants}
          initial="hidden"
          animate={inView ? "visible" : "hidden"}
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))',
            gap: 24,
          }}
        >
          {filtered.map(item => (
            <motion.div key={item.id} variants={itemVariants}>
              <TiltCard style={{ height: '100%' }}>
                <div
                  style={{
                    background: 'rgba(255,255,255,0.02)',
                    border: '1px solid rgba(201,169,110,0.1)',
                    overflow: 'hidden',
                    height: '100%',
                    transition: 'border-color 0.3s, box-shadow 0.4s',
                  }}
                  onMouseEnter={e => { e.currentTarget.style.borderColor = 'rgba(201,169,110,0.35)'; e.currentTarget.style.boxShadow = '0 24px 64px rgba(0,0,0,0.5)'; }}
                  onMouseLeave={e => { e.currentTarget.style.borderColor = 'rgba(201,169,110,0.1)'; e.currentTarget.style.boxShadow = 'none'; }}
                >
                  {/* Image */}
                  <div style={{ position: 'relative', overflow: 'hidden', height: 220 }}>
                    <img
                      src={item.image}
                      alt={item.name}
                      loading="lazy"
                      style={{ width: '100%', height: '100%', objectFit: 'cover', transition: 'transform 0.6s ease' }}
                      onMouseEnter={e => e.target.style.transform = 'scale(1.07)'}
                      onMouseLeave={e => e.target.style.transform = 'scale(1)'}
                    />
                    <div style={{
                      position: 'absolute', inset: 0,
                      background: 'linear-gradient(to bottom, transparent 50%, rgba(10,6,3,0.7) 100%)',
                    }} />
                    {/* Tag */}
                    <span style={{
                      position: 'absolute', top: 16, right: 16,
                      fontFamily: "'Jost', sans-serif", fontSize: '8px',
                      letterSpacing: '0.2em', textTransform: 'uppercase',
                      padding: '5px 10px', background: 'rgba(201,169,110,0.9)',
                      color: '#0f0a07',
                    }}>
                      {item.tag}
                    </span>
                  </div>

                  {/* Content */}
                  <div style={{ padding: '24px 28px 32px' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 12 }}>
                      <h3 style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: '22px', fontWeight: 500, color: '#f5ead8', lineHeight: 1.2 }}>
                        {item.name}
                      </h3>
                      <span style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: '20px', color: '#c9a96e', fontStyle: 'italic', whiteSpace: 'nowrap', marginLeft: 12 }}>
                        {item.price}
                      </span>
                    </div>
                    <p style={{ fontFamily: "'Jost', sans-serif", fontSize: '13px', fontWeight: 300, color: 'rgba(232,213,183,0.55)', lineHeight: 1.7, letterSpacing: '0.02em' }}>
                      {item.desc}
                    </p>
                    <div style={{ marginTop: 20, display: 'flex', alignItems: 'center', gap: 8 }}>
                      <span style={{ width: 20, height: 1, background: '#c9a96e' }} />
                      <span style={{ fontFamily: "'Jost', sans-serif", fontSize: '9px', letterSpacing: '0.2em', color: 'rgba(201,169,110,0.5)', textTransform: 'uppercase' }}>
